import{_ as i,c as e,l as a,a as t,t as l,a4 as n,o as r}from"./chunks/framework.CzsDe1xi.js";const C=JSON.parse('{"title":"git跨平台换行符设置","description":"","frontmatter":{"title":"git跨平台换行符设置"},"headers":[],"relativePath":"doc/DevOps/Git/环境搭建/git跨平台换行符设置.md","filePath":"packages/doc/src/DevOps/Git/环境搭建/git跨平台换行符设置.md","lastUpdated":1714671788000}'),h={name:"doc/DevOps/Git/环境搭建/git跨平台换行符设置.md"},p={id:"frontmatter-title",tabindex:"-1"},o=a("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),d=n(`<h2 id="目的" tabindex="-1">目的 <a class="header-anchor" href="#目的" aria-label="Permalink to &quot;目的&quot;">​</a></h2><p>为了在不同平台上开发，我们需要设置Git的换行符。换行符混用可能导致程序出现意想不到的错误。</p><h2 id="git-autocrlf" tabindex="-1">git autocrlf <a class="header-anchor" href="#git-autocrlf" aria-label="Permalink to &quot;git autocrlf&quot;">​</a></h2><p>git有一个autocrlf配置,可以在我们提交时自动转换换行符,它有3个选项:</p><ul><li>true: 提交时转换为 LF，检出时转换为 CRLF</li><li>false: 提交检出均不转换</li><li>input: 提交时转换为LF，检出时不转换为 CRLF</li></ul><p>另一个设置项safecrlf用于检查文件是否包含着混合换行符,也有3个选项:</p><ul><li>true: 拒绝提交包含混合换行符的文件</li><li>false: 允许提交包含混合换行符的文件</li><li>warn: 提交包含混合换行符的文件时给出警告 所以,如果我们要将已经加入git的大量CRLF结尾文件批量转换成LF结尾的文件,可以这样设置:</li></ul><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> core.autocrlf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> core.safecrlf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> warn</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h2 id="如何设置" tabindex="-1">如何设置 <a class="header-anchor" href="#如何设置" aria-label="Permalink to &quot;如何设置&quot;">​</a></h2><h3 id="如果始终只在各自的平台开发-可以忽略设置" tabindex="-1">如果始终只在各自的平台开发，可以忽略设置 <a class="header-anchor" href="#如果始终只在各自的平台开发-可以忽略设置" aria-label="Permalink to &quot;如果始终只在各自的平台开发，可以忽略设置&quot;">​</a></h3><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> core.autocrlf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> false</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="跨平台开发-如果当前是在linux-mac" tabindex="-1">跨平台开发，如果当前是在linux,mac <a class="header-anchor" href="#跨平台开发-如果当前是在linux-mac" aria-label="Permalink to &quot;跨平台开发，如果当前是在linux,mac&quot;">​</a></h3><p>提交时转换CRLF -&gt; LF</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> core.autocrlf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="跨平台开发-如果当前是在windows" tabindex="-1">跨平台开发，如果当前是在windows <a class="header-anchor" href="#跨平台开发-如果当前是在windows" aria-label="Permalink to &quot;跨平台开发，如果当前是在windows&quot;">​</a></h3><p>checkout时候LF -&gt; CRLF</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> core.autocrlf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这样即可保证仓库中永远都是LF. 而且在Windows工作空间都是CRLF, 在Mac/Linux工作空间都是LF.</p>`,18);function c(s,k,g,u,F,b){return r(),e("div",null,[a("h1",p,[t(l(s.$frontmatter.title)+" ",1),o]),d])}const f=i(h,[["render",c]]);export{C as __pageData,f as default};
